namespace sv_e2eb8bd0e5214a0f85be911e02568ac7.Client.Models;

public record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public record StatusUpdate(
    string Description,
    string Location,
    DateTimeOffset Timestamp);

using sv_e2eb8bd0e5214a0f85be911e02568ac7.Client.Models;

namespace sv_e2eb8bd0e5214a0f85be911e02568ac7.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_e2eb8bd0e5214a0f85be911e02568ac7.Client.Models;
using sv_e2eb8bd0e5214a0f85be911e02568ac7.Client.Services;

namespace sv_e2eb8bd0e5214a0f85be911e02568ac7.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", "New York, NY", new DateTimeOffset(2026, 5, 22, 9, 0, 0, TimeSpan.Zero)),
                new("Departed facility", "New York, NY", new DateTimeOffset(2026, 5, 22, 14, 30, 0, TimeSpan.Zero)),
                new("Arrived at sorting center", "Chicago, IL", new DateTimeOffset(2026, 5, 24, 6, 15, 0, TimeSpan.Zero)),
                new("In transit to destination", "Chicago, IL", new DateTimeOffset(2026, 5, 25, 8, 0, 0, TimeSpan.Zero)),
            }),
        ["PKG-002"] = new Shipment(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 20, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Package picked up", "Seattle, WA", new DateTimeOffset(2026, 5, 17, 10, 0, 0, TimeSpan.Zero)),
                new("In transit", "Portland, OR", new DateTimeOffset(2026, 5, 18, 12, 0, 0, TimeSpan.Zero)),
                new("Out for delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero)),
                new("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 20, 14, 22, 0, TimeSpan.Zero)),
            }),
        ["PKG-003"] = new Shipment(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new("Order confirmed", "Dallas, TX", new DateTimeOffset(2026, 5, 25, 11, 0, 0, TimeSpan.Zero)),
                new("Preparing shipment", "Dallas, TX", new DateTimeOffset(2026, 5, 25, 15, 0, 0, TimeSpan.Zero)),
            }),
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_e2eb8bd0e5214a0f85be911e02568ac7.Client.Models
@using sv_e2eb8bd0e5214a0f85be911e02568ac7.Client.Services
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-message">
        <p>@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Tracking History</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> &mdash;
                    @update.Description (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();

        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently abandon
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

